<template>
  <canvas ref="canvasEl" id="canvasEl" @mousemove="updateMousePosition" @mouseleave="resetMousePosition"/>
</template>

<script>
import { ref } from '@vue/reactivity';
import * as THREE from "../../public/js/three";
import getSpherePositions from "../../public/js/createLatticeSphere";
import Stats from 'stats.js';

export default {
  name: "BGTheme",
  setup() {
    const canvas = ref(null)
  },
  data: () => {
    return {
      then: 0,
      clearColor: 0x101028,
      fogColor: 0x000018,
      fogNear: 4,
      fogFar: 14,
      timeRotation: 0,
      mouseRotX: 0,
      mouseRotY: 0,
      mouseX: 0,
      mouseY: 0,
      velocities: []
    }
  },
  created() {
    this.createStats();
  },
  mounted() {
    this.init();

    window.addEventListener("resize", this.onResize);
  },
  unmounted() {
    window.removeEventListener("resize", this.onResize);
    this.unmounted = true;
  },
  methods: {
    init() {
      this.scene = new THREE.Scene();
      this.scene.fog = new THREE.Fog(this.fogColor, this.fogNear, this.fogFar);

      this.camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
      this.camera.position.y = 0.1;
      this.camera.position.z = 4;

      this.renderer = new THREE.WebGLRenderer({canvas: this.$refs.canvasEl});
      this.renderer.setSize(window.innerWidth, window.innerHeight);
      this.renderer.setClearColor(this.clearColor, 1);

      const sphereSize = 10;
      const pointSize = 0.1;
      this.pointSphere = this.createPointSphere(sphereSize, pointSize, 500);
      this.pointSphere.translateY(sphereSize * 0.9);
      this.scene.add(this.pointSphere);

      this.animate(0);
    },
    animate(now) {
      this.stats.begin();

      {
        now *= 0.001;
        const delta = now - this.then;
        this.then = now;

        this.pointSphere.setRotationFromQuaternion(this.getCurrentRotation(delta));

        this.renderer.render(this.scene, this.camera);
      }

      this.stats.end();
      if(!this.unmounted)
        requestAnimationFrame(this.animate);
    },
    onResize() {
				this.camera.aspect = window.innerWidth / window.innerHeight;
				this.camera.updateProjectionMatrix();
				this.renderer.setSize( window.innerWidth, window.innerHeight );
    },
    createPointSphere(sphereSize = 1, pointSize = 0.04, numPoints = 80) {
      const positions = getSpherePositions(numPoints);
      const group = new THREE.Group();

      positions.forEach(el => {
        let pos = el.multiplyScalar(sphereSize);
        let pointGeometry = new THREE.SphereGeometry(pointSize);
        pointGeometry.translate(pos.x, pos.y, pos.z);

        group.add(this.createBasicMesh(pointGeometry, 0xffffff));

        this.velocities.push(new THREE.Vector3(0, 0, 0));
      });

      return group;
    },
    createBasicMesh(geometry, color = 0xffffff) {
      const material = new THREE.MeshBasicMaterial({ color });
      return new THREE.Mesh(geometry, material);
    },
    createStats() {
      this.stats = new Stats();
      this.stats.showPanel(0);
      document.body.appendChild(this.stats.dom);
    },
    updateMousePosition(event) {
      this.mouseX = (event.pageX / window.innerWidth - 0.5) * 2;
      this.mouseY = (event.pageY / window.innerHeight - 0.5) * 2;
    },
    resetMousePosition(event) {
      this.mouseX = 0;
      this.mouseY = 0;
    },
    getCurrentRotation(delta) {
      this.mouseRotX += (this.mouseY - this.mouseRotX) / 10;
      const mouseQuatX = new THREE.Quaternion();
      mouseQuatX.setFromAxisAngle(
        new THREE.Vector3(1, 0, 0),
        this.mouseRotX * Math.PI / 32
      );

      this.mouseRotY += (this.mouseX - this.mouseRotY) / 10;
      const mouseQuatY = new THREE.Quaternion();
      mouseQuatY.setFromAxisAngle(
        new THREE.Vector3(0, 1, 0),
        this.mouseRotY * Math.PI / 8
      );

      this.timeRotation = this.timeRotation + 0.2 * delta;
      const timeQuaternion = new THREE.Quaternion();
      timeQuaternion.setFromAxisAngle(new THREE.Vector3(1, 0, 0), -this.timeRotation);

      return mouseQuatX.multiply(mouseQuatY.multiply(timeQuaternion));
    }
  }
}

</script>

<style scoped>
#canvasEl {
  position: absolute;
  top: 0;
  left: 0;
  z-index: -1;
}
</style>